const data = $input.first().json;

// Manychat envoie les custom fields du quiz
const email = data.email || '';
const prenom = data.first_name || data.prenom || '';
const interet = data.interet || data.quiz_result || data.custom_field_interet || '';
const ig_username = data.ig_username || data.username || '';

if (!email) {
  return []; // Pas d'email = on ne peut rien faire
}

return [{
  json: {
    email,
    prenom,
    interet: interet.toLowerCase().trim(),
    source: 'instagram',
    utm_source: 'instagram',
    utm_medium: 'manychat_quiz',
    ig_username
  }
}];
